import{_ as p}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as c,c as l,a as n,d as s,b as t,e}from"./app-8507340b.js";const i={},u=e('<p>자바스크립트의 모든 값은 데이터 타입을 갖는다. 데이터 타입(Data type)은 값의 종류를 말한다.</p><p>자바스크립트(ES6)은 7개의 데이터 타입을 제공하고<br> 원시 타입(Primitive type)과 객체 타입(Object/Reference type)으로 분류할 수 있다.</p><table><tr><th>구분</th><th>데이터 타입</th><th>설명</th></tr><tr><td rowspan="6">원시 타입</td><td>숫자(number)</td><td>정수와 실수 구분 없이 하나의 숫자 타입만 존재</td></tr><tr><td>문자열(string)</td><td>문자열</td></tr><tr><td>불리언(boolean)</td><td>논리적 참(true)과 거짓(false)</td></tr><tr><td>undefined</td><td>var 키워드로 선언된 변수에 암묵적으로 할당되는 값</td></tr><tr><td>null</td><td>값이 없다는 것을 의도적으로 명시할 때 사용하는 값</td></tr><tr><td>심벌(symbol)</td><td>ES6에서 추가된 7번째 타입</td></tr><tr><td colspan="2">객체 타입</td><td>객체, 함수, 배열 등</td></tr></table><p>데이터 타입에 따라 확보해야 할 메모리 공간의 크기도 다르고 메모리에 저장되는 2진수도 다르며 읽어 들여 해석하는 방식도 다르다.</p><h2 id="_1-숫자-타입" tabindex="-1"><a class="header-anchor" href="#_1-숫자-타입" aria-hidden="true">#</a> 1. 숫자 타입</h2><p>C나 자바의 경우, 정수와 실수를 구분해서 int, log, float, double 등과 같은 다양한 숫자 타입을 제공한다.</p><p>하지만 자바스크립트는 하나의 숫자타입만 존재한다.</p>',7),r={href:"https://en.wikipedia.org/wiki/Double-precision_floating-point_format",target:"_blank",rel:"noopener noreferrer"},d=e(`<figure><img src="https://github.com/Zamoca42/blog/assets/96982072/ff9bc416-9cc2-4796-8328-12a5f4345b6d" alt="IEEE 754 Double Floating Point Format" tabindex="0" loading="lazy"><figcaption>IEEE 754 Double Floating Point Format</figcaption></figure><ul><li>부호(sign): 1 bit - 0(양수), 1(음수)</li><li>지수(exponent): 11 bits - 정수 표현</li><li>가수(fraction): 52 bits - 소수점이하 자리수 표현</li></ul><p>정수, 실수, 2진수, 8진수, 16진수 리터럴은 모두 메모리에 배정밀도 64비트 부동소수점 형식의 2진수로 저장된다.</p><p>숫자 타입은 세 가지 특별한 값도 표현할 수 있다.</p><ul><li><code>Infinity</code>: 양의 무한대</li><li><code>-Infinity</code>: 음의 무한대</li><li><code>NaN</code>: 산술 연산 불가(not-a-number)</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token number">10</span> <span class="token operator">/</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Infinity</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token number">10</span> <span class="token operator">/</span> <span class="token operator">-</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// -Infinity</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token number">1</span> <span class="token operator">*</span> <span class="token string">&quot;String&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// NaN</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>📌 자바스크립트는 대소문자를 구별하므로 <code>NaN</code>을 NAN, Nan, nan으로 표현하면 변수로 인식해 에러가 발생</p><h2 id="_2-문자열-타입" tabindex="-1"><a class="header-anchor" href="#_2-문자열-타입" aria-hidden="true">#</a> 2. 문자열 타입</h2><p>문자열(String) 타입은 텍스트 데이터를 나타내는데 사용한다.<br> 문자열은 0개 이상의 16비트 유니코드 문자(UTF-16)의 집합으로 전 세계 대부분의 문자를 표현할 수 있다.</p><p>문자열은 작은따옴표(&#39;), 큰따옴표(&quot;), 백틱(\`)으로 텍스트를 감싼다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> string<span class="token punctuation">;</span>

string <span class="token operator">=</span> <span class="token string">&quot;문자열&quot;</span><span class="token punctuation">;</span>
string <span class="token operator">=</span> <span class="token string">&quot;문자열&quot;</span><span class="token punctuation">;</span>
string <span class="token operator">=</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">문자열</span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">;</span>
string <span class="token operator">=</span> <span class="token string">&#39;작은 따옴표로 감싼 문자열 내의 &quot;큰따옴표&quot;는 문자열로 인식된다.&#39;</span><span class="token punctuation">;</span>
string <span class="token operator">=</span> <span class="token string">&quot;큰따옴표로 감싼 문자열 내의 &#39;작은따옴표&#39;는 문자열로 인식된다.&quot;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>문자열을 따옴표로 감싸는 이유는 키워드나 식별자 같은 토큰과 구분하기 위해서다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> string <span class="token operator">=</span> hello<span class="token punctuation">;</span> <span class="token comment">// hello를 변수로 인식</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>자바스크립트의 문자열은 원시 타입이며, 변경 불가능한 값(Immutable value)이다.</p>`,14),k={href:"https://poiemaweb.com/js-immutability",target:"_blank",rel:"noopener noreferrer"},v=e(`<h2 id="_3-템플릿-리터럴" tabindex="-1"><a class="header-anchor" href="#_3-템플릿-리터럴" aria-hidden="true">#</a> 3. 템플릿 리터럴</h2><p>ES6부터 템플릿 리터럴(Template literal)이라고 하는 새로운 문자열 표기법이 도입되었다.<br> 템플릿 리터럴은 멀티라인 문자열, 표현식 삽입, 태그드 템플릿 등 편리한 문자열 처리 기능을 제공한다.</p><p>템플릿 리터럴은 백틱(\`)을 사용해 표현한다.</p><h3 id="_3-1-멀티라인-문자열" tabindex="-1"><a class="header-anchor" href="#_3-1-멀티라인-문자열" aria-hidden="true">#</a> 3.1. 멀티라인 문자열</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> template <span class="token operator">=</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">&lt;ul&gt;
    &lt;li&gt;&lt;a href=&quot;#&quot;&gt;Home&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;</span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>template<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>출력 결과</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>&lt;ul&gt;
    &lt;li&gt;&lt;a href=&quot;#&quot;&gt;Home&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-2-표현식-삽입" tabindex="-1"><a class="header-anchor" href="#_3-2-표현식-삽입" aria-hidden="true">#</a> 3.2. 표현식 삽입</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> first <span class="token operator">=</span> <span class="token string">&quot;Ung-mo&quot;</span><span class="token punctuation">;</span>
<span class="token keyword">var</span> last <span class="token operator">=</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">My name is </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>first<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string"> </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>last<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>출력 결과</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>My name is Ung-mo Lee
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>표현식을 삽입하려면 <code>\${}</code>으로 표현식을 감싼다. 이때 표현식의 평가결과가 문자열이 아니더라도 문자열로 강제 변환되어 삽입된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">1 + 2 = </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span><span class="token number">1</span> <span class="token operator">+</span> <span class="token number">2</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>출력</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>1 + 2 = 3
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="_4-불리언-타입" tabindex="-1"><a class="header-anchor" href="#_4-불리언-타입" aria-hidden="true">#</a> 4. 불리언 타입</h2><p>불리언 타입의 값은 <code>true</code>와 <code>false</code>로 프로그램의 흐름을 제어하는 조건문에서 주로 사용한다.</p><h2 id="_5-undefined-타입" tabindex="-1"><a class="header-anchor" href="#_5-undefined-타입" aria-hidden="true">#</a> 5. undefined 타입</h2><p><code>var</code> 키워드로 선언한 변수는 암묵적으로 <code>undefined</code>로 초기화 된다.<br> 변수를 선언한 이후 값을 할당하지 않은 변수를 참조하면 <code>undefined</code>가 반환된다.</p><p>📌 ECMAScript 사양에서 변수는 &#39;선언한다&#39;로 표현하고, 함수는 &#39;정의한다&#39;로 표현한다.</p><h2 id="_6-null-타입" tabindex="-1"><a class="header-anchor" href="#_6-null-타입" aria-hidden="true">#</a> 6. <code>null</code> 타입</h2><p>프로그래밍 언어에서 <code>null</code>은 변수에 값이 없다는 것을 의도적으로 명시할 때 사용한다.<br> 변수에 <code>null</code>을 할당하는 것은 변수가 이전에 참조하던 값을 제거하는 것의 의미다.</p><p>자바스크립트 엔진은 누구도 참조하는 메모리 공간에 대해 가비지 컬렉션을 수행할 것이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> foo <span class="token operator">=</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">;</span>

foo <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>함수가 유효한 값을 반환할 수 없는 경우 명시적으로 <code>null</code>을 반환하기도 한다.</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token doctype"><span class="token punctuation">&lt;!</span><span class="token doctype-tag">DOCTYPE</span> <span class="token name">html</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
      <span class="token keyword">var</span> element <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">querySelector</span><span class="token punctuation">(</span><span class="token string">&quot;.myClass&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
      <span class="token comment">// HTML 문서에 myClass 클래스를 갖는 요소가 없다면 null을 반환한다</span>
      console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>element<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// null</span>
    </span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_7-심벌-타입" tabindex="-1"><a class="header-anchor" href="#_7-심벌-타입" aria-hidden="true">#</a> 7. 심벌 타입</h2><p>심벌은 ES6에서 추가된 7번째 타입으로, 변경 불가능한 원시 타입의 값으로 다른 값과 중복되지 않는 유일무이한 값이다.<br> 따라서 주로 이름이 충돌할 위험이 없는 객체의 유일한 프로퍼티 키를 만들기 위해 사용한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> key <span class="token operator">=</span> <span class="token function">Symbol</span><span class="token punctuation">(</span><span class="token string">&quot;key&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> key<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// symbol</span>

<span class="token comment">// 객체 생성</span>
<span class="token keyword">var</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 이름이 충돌할 위험이 없는 유일무이한 값인 심벌을 프로퍼티 키로 사용한다</span>
obj<span class="token punctuation">[</span>key<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token string">&quot;value&quot;</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">[</span>key<span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//value</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_8-객체-타입" tabindex="-1"><a class="header-anchor" href="#_8-객체-타입" aria-hidden="true">#</a> 8. 객체 타입</h2><p>자바스크립트는 객체 기반의 언어이며, <strong>자바스크립트를 이루고 있는 거의 모든 것이 객체</strong>라는 것이다.<br> 원시 타입 이외의 값은 모두 객체 타입이다.</p><h2 id="_9-데이터-타입의-필요성" tabindex="-1"><a class="header-anchor" href="#_9-데이터-타입의-필요성" aria-hidden="true">#</a> 9. 데이터 타입의 필요성</h2><p>데이터 타입은 왜 필요한 것일까? 데이터 타입의 필요성에 대해 살펴보자.</p><h3 id="_9-1-데이터-타입에-의한-메모리-공간의-확보와-참조" tabindex="-1"><a class="header-anchor" href="#_9-1-데이터-타입에-의한-메모리-공간의-확보와-참조" aria-hidden="true">#</a> 9.1. 데이터 타입에 의한 메모리 공간의 확보와 참조</h3><p>메모리에 값을 저장하려면 먼저 확보해야 할 메모리 공간의 크기를 결정해야한다.<br> 만약 숫자 타입 값 100을 저장하려면 자바스크립트 엔진은 리터럴 100을 숫자 타입의 값으로 해석하고 100을 저장하기 위해 메모리 공간을 확보한다.<br> 그 다음 100을 2진수로 저장한다.</p><img width="666" alt="" src="https://github.com/Zamoca42/blog/assets/96982072/8156627b-47d5-4e3e-b9e7-351c8bf65a8b"><p>실제로 메모리에 저장되는 2진수 값은 그림과 다르게 배정밀도 64비트 부동소수점 형식을 사용한다.</p><h3 id="_9-2-데이터-타입에-의한-값-해석" tabindex="-1"><a class="header-anchor" href="#_9-2-데이터-타입에-의한-값-해석" aria-hidden="true">#</a> 9.2. 데이터 타입에 의한 값 해석</h3><p>모든 값은 메모리에 2진수, 즉 비트의 나열로 저장된다. 데이터 타입에 따라 메모리 공간 주소에서 읽어 들인 2진수를 해석한다.</p><h3 id="정리" tabindex="-1"><a class="header-anchor" href="#정리" aria-hidden="true">#</a> 정리</h3><p>데이터 타입이 필요한 이유는 다음과 같다</p><ul><li>값을 저장할 때 확보해야 하는 <strong>메모리 공간의 크기</strong>를 결정하기 위해</li><li>값을 참조할 때 한 번에 읽어 들여야 할 <strong>메모리 공간의 크기</strong>를 결정하기 위해</li><li>메모리에서 읽어 들인 <strong>2진수를 어떻게 해석</strong>할지 결정하기 위해</li></ul><h2 id="_10-동적-타이핑" tabindex="-1"><a class="header-anchor" href="#_10-동적-타이핑" aria-hidden="true">#</a> 10. 동적 타이핑</h2><p>C나 자바같은 정적 타입 언어는 변수를 선언할 때 변수에 할당할 수 있는 값의 종류, 즉 데이터 타입을 사전에 선언해야한다.<br> 이를 명시적 타입 선언이라 한다.</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token comment">// 1바이트 정수 타입의 값(-128 ~ 127)</span>
<span class="token keyword">char</span> c

<span class="token comment">// 정수 타입의 값(-2,124,483,648 ~ 2,124,483,647)만 할당할 수 있다.</span>
<span class="token keyword">int</span> num<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>정적 타입 언어는 변수의 타입을 변경할 수 없으며, 변수에 선언한 타입에 맞는 값만 할당할 수 있다.<br> 그리고 컴파일 시점에 타입 체크를 수행해서 타입 체크를 통과하지 못했다면 에러를 발생시키고 프로그램의 실행 자체를 막는다. 이를 통해 타입의 일관성을 강제함으로써 런타임에 발생하는 에러를 줄인다.</p><p>자바 스크립트는 정적 타입언어와 다르게 타입을 선언하지 않는다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> foo<span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>

foo <span class="token operator">=</span> <span class="token number">3</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// number</span>

foo <span class="token operator">=</span> <span class="token string">&quot;Hello&quot;</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// string</span>

foo <span class="token operator">=</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// boolean</span>

foo <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// object</span>

foo <span class="token operator">=</span> <span class="token function">Symbol</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// symbol</span>

foo <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// object</span>

foo <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// object</span>

<span class="token function-variable function">foo</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// function</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>자바스크립트의 변수에는 어떤 데이터 타입의 값이라도 자유롭게 할당할 수 있으므로 정적 타입 언어에서 말하는 데이터 타입과 개념이 다르다.</p><p>자바스크립트에서는 값을 할당하는 시점에 변수의 타입이 동적으로 결정되고 변수의 타입을 언제든지 자유롭게 변경할 수 있다.<br> 이러한 특징을 <strong>동적 타이핑</strong>이라하며, 자바스크립트를 정적 타입 언어와 구별하기 위해 <strong>동적 타입 언어</strong>라 한다.<br> 대표적인 동적 타입 언어로는 자바스크립트, 파이썬, PHP, 루비, 리스프, 펄 등이 있다.</p><h3 id="동적-타입-언어와-변수" tabindex="-1"><a class="header-anchor" href="#동적-타입-언어와-변수" aria-hidden="true">#</a> 동적 타입 언어와 변수</h3><p>동적 타입 언어는 변수의 타입이 고정되어 있지 않고 값의 변경에 의해 언제든지 변경될 수 있다.<br> 변수 값은 언제든지 변경될 수 있기 때문에 복잡한 프로그램에서는 변화하는 변수 값을 추적하기 어려울 수 있다.<br> 이러한 이유로 안정적인 프로그램을 만들기 위해 데이터 타입을 체크해야하는 경우 주의 사항은 다음과 같다.</p><ul><li>변수의 유효 범위(스코프)는 최대한 좁게 만들어 변수의 부작용을 억제</li><li>전역 변수는 최대한 사용을 자제</li><li>변수보다는 상수를 사용해 값의 변경을 억제</li><li>변수 이름은 변수의 목적이나 의미를 파악할 수 있도록 네이밍</li></ul><h2 id="추가-자료" tabindex="-1"><a class="header-anchor" href="#추가-자료" aria-hidden="true">#</a> 추가 자료</h2>`,54),m={href:"https://aeunhi99.tistory.com/323",target:"_blank",rel:"noopener noreferrer"};function b(g,h){const a=o("ExternalLinkIcon");return c(),l("div",null,[u,n("p",null,[s("ECMAScript사양에 따르면 숫자 타입의 값은 "),n("a",r,[s("배정밀도 64비트 부동소수점 형식"),t(a)]),s("을 따른다")]),d,n("p",null,[s("📌 "),n("a",k,[s("객체와 변경불가성(Immutability)"),t(a)])]),v,n("ul",null,[n("li",null,[n("a",m,[s("자바스크립트의 숫자(Number)형 - aeunhi99님의 티스토리"),t(a)])])])])}const _=p(i,[["render",b],["__file","deepdive6.html.vue"]]);export{_ as default};
